const tips = [
  "Always verify AI output – hallucination is real.",
  "Master Python and basic ML to stand out.",
  "Stay active on Hugging Face – it’s a hub for top AI models.",
  "Contribute to open-source AI projects.",
  "Learn prompt engineering – it’s one of the most in-demand AI skills right now."
];
const dailyTips = [
  "Try tools like Claude or Gemini alongside ChatGPT to compare answers.",
  "Use ChatGPT custom instructions for faster results.",
  "Experiment with vector databases like Pinecone or Weaviate.",
  "Explore LangChain for AI apps."
];

return [{
  json: {
    ai_survival_tip: tips[Math.floor(Math.random() * tips.length)],
    ai_daily_tip: dailyTips[Math.floor(Math.random() * dailyTips.length)]
  }
}];

function escapeMarkdown(text) {
  return text
    .replace(/_/g, '\\_')
    .replace(/\*/g, '\\*')
    .replace(/\[/g, '\\[')
    .replace(/\]/g, '\\]')
    .replace(/\(/g, '\\(')
    .replace(/\)/g, '\\)')
    .replace(/~/g, '\\~')
    .replace(/`/g, '\\`')
    .replace(/>/g, '\\>')
    .replace(/#/g, '\\#')
    .replace(/\+/g, '\\+')
    .replace(/-/g, '\\-')
    .replace(/=/g, '\\=')
    .replace(/\|/g, '\\|')
    .replace(/{/g, '\\{')
    .replace(/}/g, '\\}')
    .replace(/\./g, '\\.')
    .replace(/!/g, '\\!');
}

const items = $input.all();

return items.map(item => {
  const title = escapeMarkdown(item.json.title || 'No Title');
  const link = item.json.link || '';
  const pubDate = escapeMarkdown(item.json.pubDate || '');
  const summary = escapeMarkdown(
    item.json['content:encodedSnippet'] || 
    item.json.contentSnippet || 
    'No summary available.'
  );

  return {
    json: {
      formattedMessage: `📰 *${title}*\n🗓️ ${pubDate}\n\n${summary}\n\n[Read more](${link})`
    }
  };
});

const message = $json["formattedMessage"]; // replace with your field name
const maxLength = 4000; // keep a safe buffer under 4096
let parts = [];

for (let i = 0; i < message.length; i += maxLength) {
  parts.push(message.slice(i, i + maxLength));
}

return parts.map(p => ({ json: { text: p } }));
